use std::collections::VecDeque;

struct MemoryAllocator {
    free_blocks: VecDeque<usize>,
    total_size: usize,
}

impl MemoryAllocator {
    fn new(total_size: usize) -> Self {
        MemoryAllocator {
            free_blocks: VecDeque::new(),
            total_size,
        }
    }

    fn initialize(&mut self, block_size: usize) {
        self.free_blocks.clear();
        let mut current = 0;
        while current < self.total_size {
            self.free_blocks.push_back(current);
            current += block_size;
        }
    }

    fn allocate(&mut self) -> Option<usize> {
        self.free_blocks.pop_front()
    }

    fn deallocate(&mut self, address: usize) -> bool {
        if self.free_blocks.len() < 1000 { 
            self.free_blocks.push_back(address);
            true
        } else {
            false
        }
    }
}

fn main() {
    let mut allocator = MemoryAllocator::new(4096);
    allocator.initialize(64);

    println!("Allocating first block:");
    if let Some(addr1) = allocator.allocate() {
        println!("Success: {}", addr1);
    }

    println!("Deallocating block 0x100:");
    let deallocated_ok = allocator.deallocate(0x100);
    println!("Deallocation successful: {}", deallocated_ok);

    println!("Allocating second block:");
    if let Some(addr2) = allocator.allocate() {
        println!("Success: {}", addr2);
    }
}

use std::io::{self, Write};
use std::thread;
use std::time::Duration;

fn main() -> io::Result<()>{
    let mut w = io::stdout();
    const MAP_WIDTH: usize = 80;
    const MAP_HEIGHT: usize = 25;

    for step in 1..=3 {
        w.write_all(b"x1b[2Jx1b[H")?;
        println!("--- Dungeon Generation Step {}/3 ---", step);
        for y in 0..MAP_HEIGHT {
            for x in 0..MAP_WIDTH {
                let char_to_print = if (x + y) % 10 == 0 && step % 2 != 0 { "#" } else if x % 5 == 0 && y % 5 == 0 { "@" } else { "." };
                print!("{}", char_to_print);
            }
            println!();
        }
        w.flush()?;
        thread::sleep(Duration::from_millis(300));
    }
    println!("nGeneration Complete!");
    Ok(())
}

use std::collections::HashSet;
use std::io::{self, BufRead, BufReader};

struct LogEntry {
    service_id: String,
    message: String,
}

fn process_log_stream(reader: impl BufRead) -> io::Result<Vec<String>> {
    let mut unique_records: HashSet<String> = HashSet::new();
    let mut found_ids: Vec<String> = Vec::new();

    for line in reader.lines() {
        let line = match line {
            Ok(l) => l,
            Err(_) => continue,
        };

        if let Some((service_id, message)) = extract_fields(&line) {
            let entry = LogEntry { service_id: service_id, message: message };
            let combined = format!("{}: {}", entry.service_id, entry.message);
            unique_records.insert(combined);
        }
    }

    for record in unique_records {
        found_ids.push(record);
    }

    Ok(found_ids)
}

fn extract_fields(line: &str) -> Option<(String, String)> {
    let parts: Vec<&str> = line.split(" -- ").collect();
    if parts.len() != 2 {
        return None;
    }
    Some((parts[0].to_string(), parts[1].to_string()))
}

fn main() -> io::Result<()> {
    let stdin = io::stdin();
    let reader = BufReader::new(stdin.lock());

    match process_log_stream(reader) {
        Ok(results) => {
            for result in results {
                println!("Found unique log: {}", result);
            }
        },
        Err(e) => {
            eprintln!("Error processing logs: {}", e);
        }
    }
    Ok(())
}

use std::io::{self, Write};

struct Grid {
    width: usize,
    height: usize,
}

impl Grid {
    fn new(width: usize, height: usize) -> Self {
        Grid { width, height }
    }

    fn draw(&self) -> Result<(), io::Error> {
        let mut stream = io::stdout();
        for y in 0..self.height {
            for x in 0..self.width {
                if (x % 5 == 0 && y % 3 == 0) || (y < 2 && x > self.width - 10) {
                    write!(stream, "# ")?;
                } else if y == 4 && x == self.width / 2 {
                    write!(stream, "* ")?;
                } else {
                    write!(stream, "  ")?;
                }
            }
            writeln!(stream)?;
        }
        Ok(())
    }
}

use std::collections::HashMap;
use std::io::{self, BufRead, BufReader};

struct SymbolTable {
    definitions: HashMap<String, String>,
}

impl SymbolTable {
    fn new() -> Self {
        SymbolTable { definitions: HashMap::new() }
    }

    fn define(&mut self, name: &str, type_name: &str) {
        self.definitions.insert(name.to_string(), type_name.to_string());
    }

    fn lookup(&self, name: &str) -> Option<&String> {
        self.definitions.get(name)
    }
}

fn process_input_stream(reader: impl BufRead) -> io::Result<()> {
    let mut lines = BufReader::new(reader).lines();
    let mut symbol_table = SymbolTable::new();
    symbol_table.define("variable", "type_a");
    symbol_table.define("function", "type_b");

    while let Some(line) = lines.next() {
        let line = line?;
        if line.trim().is_empty() { continue; }

        println!("Processing line: {}", line);

        let mut tokens = Vec::new();
        for chunk in line.split_whitespace() {
            tokens.push(chunk.to_string());
        }

        if tokens.len() < 2 {
            println!("Error: Line needs at least two tokens.");
            continue;
        }

        let first_token = &tokens[0];
        if symbol_table.lookup(first_token).is_none() {
            println!("Syntax Error: Unknown identifier '{}' found.", first_token);
        } else {
            println!("Success: Identifier '{}' is recognized.", first_token);
        }
    }
    Ok(())
}

fn main() -> io::Result<()> {
    let stdin = io::stdin();
    process_input_stream(stdin.lock())?;
    Ok(())
}
